using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed — Cosmos DB provider now throws at startup.
        // Manage indexing via the Azure Portal or infrastructure-as-code.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve EF Core 8 discriminator property name ("Discriminator")
            // so existing documents and direct SQL queries (c.Discriminator) keep working.
            // EF Core 9 defaults to "$type".
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF Core 8 compound id format ("Product|123")
            // so existing 500K documents remain accessible via FindAsync / point-reads.
            // EF Core 9 defaults to key-only ids ("123").
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

